### Protected Routes

Protected routes control access based on authentication or authorization. Unauthenticated users are redirected to login.

---

### ProtectedRoute Component

```jsx
import { Navigate, Outlet } from 'react-router-dom';

function ProtectedRoute({ isAuthenticated, redirectTo = '/login' }) {
  if (!isAuthenticated) {
    return <Navigate to={redirectTo} replace />;
  }
  return <Outlet />;
}
```

### Route Configuration

```jsx
import { useAuth } from './hooks/useAuth';

function AppRoutes() {
  const { user } = useAuth();

  return (
    <Routes>
      <Route path="/login" element={<Login />} />
      <Route path="/register" element={<Register />} />

      <Route element={<ProtectedRoute isAuthenticated={!!user} />}>
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="/profile" element={<Profile />} />
        <Route path="/settings" element={<Settings />} />
      </Route>

      <Route path="*" element={<NotFound />} />
    </Routes>
  );
}
```

### Role-Based Access

```jsx
function RoleRoute({ allowedRoles }) {
  const { user } = useAuth();

  if (!user) return <Navigate to="/login" replace />;
  if (!allowedRoles.includes(user.role)) return <Navigate to="/unauthorized" replace />;

  return <Outlet />;
}

// Usage
<Route element={<RoleRoute allowedRoles={['admin', 'manager']} />}>
  <Route path="/admin" element={<AdminPanel />} />
</Route>
```

### Auth Context Provider

```jsx
function AuthProvider({ children }) {
  const [user, setUser] = useState(null);

  const login = async (credentials) => {
    const user = await authApi.login(credentials);
    setUser(user);
  };

  const logout = () => {
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}
```

| Pattern | Description |
|---------|-------------|
| Auth guard | Redirect to login if not authenticated |
| Role guard | Redirect if user lacks required role |
| Layout outlet | Protected routes share a layout |

> **Key Point:** Protected routes wrap child routes. The `<Navigate>` component with `replace` prevents the login page from appearing in the browser's back history. Always validate auth on the server too.

codeExample:
import { Navigate, Outlet } from 'react-router-dom';

function ProtectedLayout() {
  const token = localStorage.getItem('token');

  if (!token) {
    return <Navigate to="/login" state={{ from: location }} replace />;
  }

  return (
    <div>
      <header>App Header</header>
      <Outlet />
    </div>
  );
}
